{
  "review_plan": {
    "description": "Set pam_pwquality minclass to 3 to enforce at least three different character classes in passwords"
  },
  "read_file": {
    "path": "/etc/security/pwquality.conf.d/pwquality.conf"
  },
  "run_cmd": {
    "command": "sed -i 's/^minclass.*/minclass=3/' /etc/security/pwquality.conf.d/pwquality.conf"
  },
  "write_file": {
    "path": "/etc/security/pwquality.conf.d/pwquality.conf",
    "content": "The file /etc/security/pwquality.conf.d/pwquality.conf with the minclass parameter set to 3"
  }
}

